    let route = match routes.get(&(host.as_str(), path.as_str())) {
        Some(r) => *r,
        None => match routes.get(&(host.as_str(), "*")) {
            Some(r) => *r,
            None => match routes.get(("*", "*")) {
                Some(r) => *r,
                None => {
                    return Ok(Response::from_status(StatusCode::NOT_FOUND)
                        .with_body_text_plain("No route\n"))
                }
            },
        },
    };

    let backend = ensure_backend(route)?;

    req.remove_header(header::CONNECTION);
    req.remove_header(header::PROXY_CONNECTION);
    req.remove_header(header::KEEP_ALIVE);
    req.remove_header(header::TRANSFER_ENCODING);
    req.remove_header(header::TE);
    req.remove_header(header::TRAILER);
